const ids = $input.first().json;
const top5 = Array.isArray(ids) ? ids.slice(0, 5) : [];
return top5.map(id => ({ json: { id, url: `https://hacker-news.firebaseio.com/v0/item/${id}.json` } }));

const stories = $input.all();
const lines = stories.map((item, i) => {
  const s = item.json;
  const title = s.title || 'No title';
  const url = s.url || `https://news.ycombinator.com/item?id=${s.id}`;
  const score = s.score || 0;
  const by = s.by || 'unknown';
  return `*${i + 1}. <${url}|${title}>*\n⬆️ ${score} points by ${by}`;
});
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const message = `📰 *Hacker News Top 5 — ${date}*\n\n` + lines.join('\n\n');
return [{ json: { message } }];

const stories = $input.all();
const lines = stories.map((item, i) => {
  const s = item.json;
  const title = s.title || 'No title';
  const url = s.url || `https://news.ycombinator.com/item?id=${s.id}`;
  const score = s.score || 0;
  const by = s.by || 'unknown';
  return `${i + 1}. ${title} (${url}) — ⬆️ ${score} points by ${by}`;
});
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
return [{ json: { storyList: lines.join('\n'), date } }];

const stories = $input.all();
const count = stories.length;
const date = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const sorted = [...stories].sort((a, b) => (b.json.score || 0) - (a.json.score || 0));
const rows = sorted.map((item, i) => {
  const s = item.json;
  const title = s.title || 'No title';
  const url = s.url || `https://news.ycombinator.com/item?id=${s.id}`;
  const score = s.score || 0;
  const by = s.by || 'unknown';
  return `<tr><td style="padding:8px 12px;font-weight:bold;color:#ff6600;">${i + 1}</td><td style="padding:8px 12px;"><a href="${url}" style="color:#1a0dab;text-decoration:none;">${title}</a></td><td style="padding:8px 12px;text-align:center;">⬆️ ${score}</td><td style="padding:8px 12px;color:#555;">${by}</td></tr>`;
}).join('');
const html = `<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;"><h2 style="color:#ff6600;border-bottom:2px solid #ff6600;padding-bottom:8px;">📰 Hacker News Digest — ${date}</h2><p style="color:#333;font-size:15px;"><strong>${count} stories</strong> fetched and ranked by score (highest first):</p><table style="width:100%;border-collapse:collapse;background:#f9f9f9;"><thead><tr style="background:#ff6600;color:#fff;"><th style="padding:8px 12px;text-align:left;">#</th><th style="padding:8px 12px;text-align:left;">Title</th><th style="padding:8px 12px;text-align:center;">Score</th><th style="padding:8px 12px;text-align:left;">Author</th></tr></thead><tbody>${rows}</tbody></table><p style="color:#888;font-size:12px;margin-top:16px;">Generated automatically by your HN Digest automation on ${date}.</p></div>`;
return [{ json: { html, count, date } }];
